class Solution {
public:
    int orangesRotting(vector<vector<int>>& grid) {
        int turns = 0;
        int oranges = 0;
        int rotorange = 0;
        int n = grid.size();
        int m = grid[0].size();
        vector<int> dx = {-1, 0, 1, 0};
        vector<int> dy = {0, 1, 0, -1};
        queue<pair<int, int>> q;

        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < m; ++j) {
                if (grid[i][j]) {
                    oranges++;
                }
                if (grid[i][j] == 2) {
                    rotorange++;
                    q.push({i, j});
                }
            }
        }

        if (rotorange == oranges)
            return 0; 

        while (!q.empty()) {
            int size = q.size();
            turns++;
            while (size--) {
                auto curr = q.front();
                q.pop();
                int i = curr.first;
                int j = curr.second;
                for (int k = 0; k < 4; ++k) {
                    int new_i = i + dx[k];
                    int new_j = j + dy[k];
                    if (new_i >= 0 && new_i < n && new_j >= 0 && new_j < m && grid[new_i][new_j] == 1) {
                        rotorange++;
                        grid[new_i][new_j] = 2; 
                        q.push({new_i, new_j});
                    }
                }
            }
        }
        return (rotorange == oranges) ? turns - 1 : -1;
    }
};
